import type { InjectionKey } from "vue";
import { PGlite } from "@electric-sql/pglite";
import { live } from "@electric-sql/pglite/live";
import { provide } from "vue";

const PGLiteKey = Symbol("PGlite") as InjectionKey<PGlite>;

function provideDb() {
  const db = new PGlite("idb://bus-station-db", {
    extensions: {
      live,
    },
  });

  provide(PGLiteKey, db);

  return db;
}

async function initDb(db: PGlite) {
  await db.exec(`
    CREATE TABLE IF NOT EXISTS "role" (
        role_id SERIAL PRIMARY KEY,
        title VARCHAR(20) UNIQUE NOT NULL
    );
    CREATE TABLE IF NOT EXISTS employee (
        employee_id SERIAL PRIMARY KEY,
        role_id INT NOT NULL REFERENCES role(role_id),
        surname VARCHAR(50) NOT NULL,
        "name" VARCHAR(50) NOT NULL,
        patronymic VARCHAR(50),
        phone_number VARCHAR(20) UNIQUE NOT NULL
    );
    CREATE TABLE IF NOT EXISTS shift (
        shift_id SERIAL PRIMARY KEY,
        employee_id INT NOT NULL REFERENCES employee(employee_id),
        start_time TIMESTAMPTZ NOT NULL,
        end_time TIMESTAMPTZ NOT NULL CHECK (end_time > start_time)
    );
    CREATE TABLE IF NOT EXISTS customer (
        customer_id SERIAL PRIMARY KEY,
        surname VARCHAR(50) NOT NULL,
        "name" VARCHAR(50) NOT NULL,
        patronymic VARCHAR(50),
        phone_number VARCHAR(20) UNIQUE NOT NULL,
        passport_data VARCHAR(20) UNIQUE NOT NULL
    );
    CREATE TABLE IF NOT EXISTS carrier (
        carrier_id SERIAL PRIMARY KEY,
        title VARCHAR(150) UNIQUE NOT NULL,
        contact_phone VARCHAR(20) UNIQUE NOT NULL
    );
    CREATE TABLE IF NOT EXISTS bus (
        bus_id SERIAL PRIMARY KEY,
        carrier_id INT NOT NULL REFERENCES carrier(carrier_id),
        brand VARCHAR(50) NOT NULL,
        model VARCHAR(50) NOT NULL,
        capacity INT NOT NULL,
        plate_number VARCHAR(10) UNIQUE NOT NULL
    );
    CREATE TABLE IF NOT EXISTS bus_stop (
        bus_stop_id SERIAL PRIMARY KEY,
        title VARCHAR(50) UNIQUE NOT NULL
    );
    CREATE TABLE IF NOT EXISTS route (
        route_id SERIAL PRIMARY KEY,
        title VARCHAR(50) NOT NULL,
        total_time INT NOT NULL
    );
    CREATE TABLE IF NOT EXISTS route_stop (
        route_stop_id SERIAL PRIMARY KEY,
        route_id INT NOT NULL REFERENCES route(route_id),
        bus_stop_id INT NOT NULL REFERENCES bus_stop(bus_stop_id),
        stop_order INT NOT NULL,
        travel_time INT NOT NULL
    );
    CREATE TABLE IF NOT EXISTS driver (
        driver_id SERIAL PRIMARY KEY,
        surname VARCHAR(50) NOT NULL,
        "name" VARCHAR(50) NOT NULL,
        patronymic VARCHAR(50),
        phone_number VARCHAR(20) UNIQUE NOT NULL
    );
    CREATE TABLE IF NOT EXISTS trip (
        trip_id SERIAL PRIMARY KEY,
	    driver_id INT NOT NULL REFERENCES driver(driver_id),
        bus_id INT NOT NULL REFERENCES bus(bus_id),
        route_id INT NOT NULL REFERENCES route(route_id),
        departure_time TIMESTAMPTZ NOT NULL
    );
    CREATE TABLE IF NOT EXISTS ticket (
        ticket_id SERIAL PRIMARY KEY,
        trip_id INT NOT NULL REFERENCES trip(trip_id),
        shift_id INT NOT NULL REFERENCES shift(shift_id),
        customer_id INT NOT NULL REFERENCES customer(customer_id),
        bus_stop_in_id INT NOT NULL REFERENCES bus_stop(bus_stop_id),
        bus_stop_out_id INT NOT NULL REFERENCES bus_stop(bus_stop_id),
        purchase_date TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
        price DECIMAL(10, 2) NOT NULL,
        seat_number VARCHAR(5) NOT NULL,
        status VARCHAR(15) NOT NULL
    );`);
}

